import{c as a,Q as e,j as t,m as i}from"./chunks/framework.rlpw0eGz.js";const c=JSON.parse('{"title":"Workspace Backends","description":"","frontmatter":{},"headers":[],"relativePath":"installation/workspace-backends.md","filePath":"installation/workspace-backends.md","lastUpdated":1780209430000}'),n={name:"installation/workspace-backends.md"};function o(r,s,l,d,p,h){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="workspace-backends" tabindex="-1">Workspace Backends <a class="header-anchor" href="#workspace-backends" aria-label="Permalink to &quot;Workspace Backends&quot;">​</a></h1><p>Each Memoh bot works inside a workspace. A workspace may be an isolated container or, in trusted desktop/local scenarios, a host local directory. The backend decides where that workspace runs and which isolation, networking, snapshot, and display features are available.</p><h2 id="container-backends" tabindex="-1">Container backends <a class="header-anchor" href="#container-backends" aria-label="Permalink to &quot;Container backends&quot;">​</a></h2><p>Configure container workspaces in <code>config.toml</code>:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">backend = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;containerd&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # containerd, docker, or apple</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Backend</th><th>Best fit</th><th>Notes</th></tr></thead><tbody><tr><td><code>containerd</code></td><td>Docker Compose server deploys, Linux servers, development</td><td>Default for the official server image. Supports CNI networking, snapshots, CDI devices, provider sidecars, and the broadest local workspace feature set.</td></tr><tr><td><code>docker</code></td><td>Host/binary deployments with Docker Engine</td><td>Uses the host Docker API. Runtime bind-mount paths such as <code>container.runtime_dir</code> must exist on the Docker host.</td></tr><tr><td><code>apple</code></td><td>macOS local testing</td><td>Uses socktainer and Apple Containerization. Overlay provider sidecars are not supported.</td></tr></tbody></table><p>The one-click Docker Compose server deploy uses <code>containerd</code>. That is intentional: the server image starts an embedded containerd and mounts the runtime files needed by bot workspaces. Use the other backends for manual deployments where you control the host runtime paths.</p><h2 id="trusted-local-workspaces" tabindex="-1">Trusted local workspaces <a class="header-anchor" href="#trusted-local-workspaces" aria-label="Permalink to &quot;Trusted local workspaces&quot;">​</a></h2><p>Desktop and local development can enable trusted local workspaces alongside the configured container backend:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">local</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>Trusted local workspaces run on the host with the server process permissions. They are useful for personal desktop workflows and local development, but they are <strong>not container-isolated</strong>. Do not enable local workspaces for untrusted server deployments.</p><p>When a bot uses a local workspace, UI affordances that require a container desktop or container display session may be hidden or unavailable.</p><h2 id="containerd" tabindex="-1">containerd <a class="header-anchor" href="#containerd" aria-label="Permalink to &quot;containerd&quot;">​</a></h2><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">backend = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;containerd&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">default_image = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;debian:bookworm-slim&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">image_pull_policy = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;if_not_present&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">snapshotter = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;overlayfs&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">data_root = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/opt/memoh/data&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">runtime_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/opt/memoh/runtime&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cni_bin_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/opt/cni/bin&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cni_conf_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/etc/cni/net.d&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">containerd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">socket_path = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/run/containerd/containerd.sock&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">namespace = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;default&quot;</span></span></code></pre></div><p>Use this backend for the official Docker Compose stack and for hosts where Memoh can talk directly to containerd.</p><h2 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h2><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">backend = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;docker&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">default_image = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;debian:bookworm-slim&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">runtime_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/opt/memoh/runtime&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">data_root = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/opt/memoh/data&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Empty means Docker&#39;s standard environment discovery: DOCKER_HOST,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># DOCKER_TLS_VERIFY, DOCKER_CERT_PATH, or the platform default socket.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">host = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span></code></pre></div><p>The Docker backend talks to Docker Engine through the standard Docker environment. It is meant for a Memoh server running on the host or in an environment where Docker bind-mount source paths refer to real host paths.</p><p>Avoid switching a stock Docker Compose install from <code>containerd</code> to <code>docker</code> unless you also provide host-valid paths for <code>runtime_dir</code> and Docker socket access. Otherwise the workspace containers can be created without the bridge runtime files they need.</p><h2 id="apple" tabindex="-1">Apple <a class="header-anchor" href="#apple" aria-label="Permalink to &quot;Apple&quot;">​</a></h2><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">backend = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;apple&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apple</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">socket_path = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">binary_path = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span></code></pre></div><p>This backend is for local macOS testing through socktainer and Apple Containerization. It is experimental and does not support provider-backed network sidecars.</p><h2 id="display-browser-use-and-computer-use" tabindex="-1">Display, Browser Use, and Computer Use <a class="header-anchor" href="#display-browser-use-and-computer-use" aria-label="Permalink to &quot;Display, Browser Use, and Computer Use&quot;">​</a></h2><p>Container workspaces can provide a display runtime: Xvnc/RFB for the workspace desktop, a headed Chrome/Chromium browser with CDP, and WebRTC sessions for the Web UI display pane.</p><p>Use this path when a site needs a real graphical browser. Headless Playwright remains available as an ordinary workspace command, but Browser Use and Computer Use target the headed workspace desktop.</p><p>Local workspaces do not provide the same container desktop isolation. Use <a href="/getting-started/browser-computer-use.html">Browser / Computer Use</a> for the tool-level model.</p><h2 id="networking-and-overlays" tabindex="-1">Networking and overlays <a class="header-anchor" href="#networking-and-overlays" aria-label="Permalink to &quot;Networking and overlays&quot;">​</a></h2><p>Bot networking has two layers:</p><ul><li>Runtime networking connects the workspace to the base container or pod network.</li><li>Overlay providers such as Tailscale and NetBird attach optional per-bot private networking.</li></ul><p>Runtime capabilities differ by backend:</p><table tabindex="0"><thead><tr><th>Backend</th><th>Runtime network</th><th>Overlay sidecars</th><th>CDI devices</th><th>Container display</th></tr></thead><tbody><tr><td><code>containerd</code></td><td>CNI</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td><code>docker</code></td><td>Join Docker container network</td><td>Limited by Docker runtime capabilities</td><td>No</td><td>Yes, when runtime files and image packages are available</td></tr><tr><td><code>apple</code></td><td>Basic local runtime</td><td>No</td><td>No</td><td>Limited</td></tr><tr><td><code>local</code></td><td>Host network</td><td>No</td><td>Host-level only</td><td>No container desktop</td></tr></tbody></table><p>Overlay provider settings are configured per bot in the web UI, not in the global TOML file. The global backend still matters because it decides which overlay driver can run.</p>`,32)])])}const E=a(n,[["render",o]]);export{c as __pageData,E as default};
